Here’s how you can use `update` with a condition to mimic `put` behavior:
javascript
var AWS = require('aws-sdk');
AWS.config.update({region: "us-east-1"});
const docClient = new DynamoDB.DocumentClient();

let params = {
  TableName: TABLE_NAME,
  Key: {"year": 2021},
  UpdateExpression: "SET #title = :title",
  ExpressionAttributeNames: {"#title": "title"},
  ExpressionAttributeValues: {":title": "Title A", ":year": 2021},
  ConditionExpression: "attribute_not_exists(year)",
  ReturnValues: "ALL_NEW"
};

let promise = docClient.update(params).promise();
promise.then(res => {
  console.log("res:", res);
});
